import{_ as a,o,c as t,a0 as r}from"./chunks/framework.BH9V8Et6.js";const u=JSON.parse('{"title":"Changelog","description":"","frontmatter":{},"headers":[],"relativePath":"changelog.md","filePath":"changelog.md"}'),l={name:"changelog.md"};function i(c,e,n,d,s,h){return o(),t("div",null,[...e[0]||(e[0]=[r('<h1 id="changelog" tabindex="-1">Changelog <a class="header-anchor" href="#changelog" aria-label="Permalink to &quot;Changelog&quot;">​</a></h1><h2 id="v0-2-0" tabindex="-1">v0.2.0 <a class="header-anchor" href="#v0-2-0" aria-label="Permalink to &quot;v0.2.0&quot;">​</a></h2><p>Browser rendering, crawl, and cache overhaul.</p><ul><li><strong>Browser rendering</strong>: JS-rendered pages (React, Angular, Salesforce Lightning) automatically detected and re-fetched via headless Chrome using Rod <ul><li><code>ketch config set browser chrome</code> — configure browser</li><li><code>ketch browser install</code> — download Chromium</li><li><code>ketch browser status</code> — check browser availability</li><li>Detection heuristic: visible text, noscript tags, SPA markers, script-to-text ratio, loading page detection</li><li>Transparent fallback — agents see the same output format</li></ul></li><li><strong>Crawl command</strong>: BFS and sitemap-based site crawling <ul><li><code>ketch crawl &lt;url&gt;</code> — BFS crawl with configurable depth and concurrency</li><li><code>ketch crawl &lt;url&gt; --sitemap</code> — sitemap-based crawl</li><li><code>ketch crawl &lt;url&gt; --background</code> — detached process with status tracking</li><li><code>ketch crawl status</code> / <code>ketch crawl stop</code> — monitor and control background crawls</li><li>Per-host JS shell tracking: auto-switches to browser mode when &gt;80% of pages are JS-rendered</li><li>Cached re-crawls complete in under a second</li></ul></li><li><strong>Cache backend</strong>: migrated from filesystem (one file per page) to embedded bbolt database <ul><li>Single <code>cache.db</code> file instead of thousands of hashed files</li><li><code>Store</code> interface for future backend support (redis, etc.)</li><li>Default TTL changed from 1h to 72h</li><li>Shared cache between scrape and crawl commands</li></ul></li><li><strong>Config</strong>: added <code>browser</code> key for browser configuration</li></ul><h2 id="v0-1-0" tabindex="-1">v0.1.0 <a class="header-anchor" href="#v0-1-0" aria-label="Permalink to &quot;v0.1.0&quot;">​</a></h2><p>Initial release.</p><ul><li>Search via Brave, DuckDuckGo, or SearXNG</li><li>Scrape URLs to clean markdown (readability + html-to-markdown)</li><li>Concurrent batch scraping</li><li>YAML frontmatter + markdown output format</li><li>JSON config at <code>~/.config/ketch/config.json</code></li><li>TTL-based page cache with platform-correct paths</li><li><code>ketch config</code> discovery payload for agent introspection</li><li><code>--json</code> flag on all commands</li><li>GoReleaser + Homebrew tap publishing</li></ul>',7)])])}const m=a(l,[["render",i]]);export{u as __pageData,m as default};
